#include <stdio.h>
#include <stdlib.h>

int max(int a, int b) { return (a > b) ? a : b; }

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int* A = (int*) malloc(N * sizeof(int));
        int* B = (int*) malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        for (int i = 0; i < N; i++) {
            scanf("%d", &B[i]);
        }
        int** dp = (int**) malloc(N * sizeof(int*));
        for (int i = 0; i < N; i++) {
            dp[i] = (int*) malloc(N * sizeof(int));
        }
        int maxLen = 0;
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < N; j++) {
                if (A[i] == B[j]) {
                    if (i == 0 || j == 0) {
                        dp[i][j] = 1;
                    } else {
                        dp[i][j] = dp[i-1][j-1] + 1;
                    }
                    maxLen = max(maxLen, dp[i][j]);
                }
            }
        }
        printf("%d\n", maxLen);
        free(A);
        free(B);
        for (int i = 0; i < N; i++) {
            free(dp[i]);
        }
        free(dp);
    }
    return 0;
}

